import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Edit, Save, 
  X, Loader2, AlertCircle, Crown, Users, Key, ChevronDown
} from 'lucide-react';

const Perfil = () => {
  const [perfil, setPerfil] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [loading, setLoading] = useState(true);
  const [novoNome, setNovoNome] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();

      if (!user) {
        setErroLocal("Sessão expirada. Faça login novamente.");
        return;
      }

      const { data: meuPerfil, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', user.id)
        .maybeSingle();

      if (profileError) throw profileError;

      if (meuPerfil) {
        setPerfil(meuPerfil);
        setNovoNome(meuPerfil.nome || '');

        // Se for proprietário, carrega todos (incluindo ele mesmo para a lista)
        if (meuPerfil.tipo_usuario === 'proprietario') {
          const { data: lista } = await supabase
            .from('profiles')
            .select('*')
            .order('nome', { ascending: true });
          
          if (lista) setUsuarios(lista);
        }
      }
    } catch (err) {
      setErroLocal("Não foi possível carregar os dados.");
    } finally {
      setLoading(false);
    }
  };

  const atualizarNome = async () => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ nome: novoNome })
        .eq('id', perfil.id);

      if (error) throw error;
      setPerfil({ ...perfil, nome: novoNome });
      alert("Suas informações foram atualizadas!");
    } catch (err) {
      alert("Erro ao atualizar o nome.");
    }
  };

  const alterarSenha = async () => {
    if (novaSenha.length < 6) {
      alert("A senha deve ter pelo menos 6 caracteres.");
      return;
    }
    try {
      const { error } = await supabase.auth.updateUser({ password: novaSenha });
      if (error) throw error;
      alert("Senha alterada com sucesso!");
      setNovaSenha('');
    } catch (err) {
      alert("Erro ao alterar senha: " + err.message);
    }
  };

  const mudarCargo = async (usuarioId, novoCargo) => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ tipo_usuario: novoCargo })
        .eq('id', usuarioId);

      if (error) throw error;
      
      // Atualiza a lista localmente
      setUsuarios(usuarios.map(u => u.id === usuarioId ? { ...u, tipo_usuario: novoCargo } : u));
      
      // Se eu mudei meu próprio cargo (improvável pelo layout, mas por segurança):
      if (usuarioId === perfil.id) {
        setPerfil({ ...perfil, tipo_usuario: novoCargo });
      }
    } catch (err) {
      alert("Erro ao mudar cargo.");
    }
  };

  const excluirUsuario = async (id, nome) => {
    if (id === perfil.id) return;
    if (window.confirm(`Excluir permanentemente o acesso de ${nome}?`)) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) {
        setUsuarios(usuarios.filter(u => u.id !== id));
      }
    }
  };

  if (loading) return (
    <div style={containerCenter}>
      <Loader2 className="animate-spin" size={48} color="#2d6a4f" />
      <p style={{ color: '#64748b' }}>Carregando informações...</p>
    </div>
  );

  return (
    <div style={{ padding: '40px 20px', maxWidth: '1000px', margin: '0 auto', paddingBottom: '100px' }}>
      <header style={{ marginBottom: '30px', borderBottom: '2px solid #ffcc00', paddingBottom: '15px' }}>
        <h1 style={{ color: '#1b4332', fontSize: '2rem', fontWeight: 800 }}>Funcionários</h1>
      </header>

      {/* SEÇÃO 1: MEUS DADOS (FOTO 03) */}
      <section style={{ marginBottom: '50px' }}>
        <h3 style={listTitleStyle}>Suas Informações</h3>
        <div style={mainCardStyle}>
          <div style={{ display: 'flex', gap: '20px', alignItems: 'flex-start' }}>
            <div style={avatarCircle}>
               <User size={30} color="#1b4332" />
            </div>
            <div style={{ flex: 1 }}>
              <div style={{ marginBottom: '15px' }}>
                <label style={labelStyle}>Nome Completo</label>
                <div style={{ display: 'flex', gap: '10px' }}>
                  <input 
                    value={novoNome} 
                    onChange={(e) => setNovoNome(e.target.value)}
                    style={inputStyle}
                  />
                  <button onClick={atualizarNome} style={btnSaveStyle} title="Salvar">
                    <Save size={18} />
                  </button>
                </div>
              </div>

              <div style={infoGrid}>
                <div>
                  <label style={labelStyle}>E-mail</label>
                  <div style={infoValue}>{perfil?.email}</div>
                </div>
                <div>
                  <label style={labelStyle}>Tipo</label>
                  <div style={badgeStyle(perfil?.tipo_usuario)}>{perfil?.tipo_usuario}</div>
                </div>
              </div>

              <div style={{ marginTop: '20px', paddingTop: '20px', borderTop: '1px solid #eee' }}>
                <label style={labelStyle}>Segurança (Trocar Senha)</label>
                <div style={{ display: 'flex', gap: '10px', marginTop: '5px' }}>
                  <input 
                    type="password" 
                    placeholder="Nova senha" 
                    value={novaSenha}
                    onChange={(e) => setNovaSenha(e.target.value)}
                    style={{ ...inputStyle, maxWidth: '200px' }}
                  />
                  <button onClick={alterarSenha} style={btnPassStyle}>Alterar Senha</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* SEÇÃO 2: LISTA GERAL (FOTO 01/02) - APENAS PROPRIETÁRIO VÊ */}
      {perfil?.tipo_usuario === 'proprietario' && (
        <section>
          <h3 style={listTitleStyle}>Lista de Funcionários</h3>
          <div style={userGridStyle}>
            {usuarios.map(u => (
              <div key={u.id} style={userCardStyle}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '12px' }}>
                  <div style={smallAvatarStyle}>{u.nome?.charAt(0)}</div>
                  <div style={{ fontWeight: 700, color: '#1b4332' }}>{u.nome}</div>
                </div>
                
                <div style={userCardContent}>
                  <p><strong>E-mail:</strong> {u.email}</p>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginTop: '10px' }}>
                    <strong>Tipo:</strong>
                    {u.id !== perfil.id ? (
                      <div style={selectWrapper}>
                        <select 
                          value={u.tipo_usuario} 
                          onChange={(e) => mudarCargo(u.id, e.target.value)}
                          style={selectStyle}
                        >
                          <option value="comum">Comum</option>
                          <option value="proprietario">Administrador</option>
                        </select>
                      </div>
                    ) : (
                      <span style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario} (Você)</span>
                    )}
                  </div>
                </div>

                {u.id !== perfil.id && (
                  <button onClick={() => excluirUsuario(u.id, u.nome)} style={deleteBtnStyle}>
                    <Trash2 size={16} /> Remover
                  </button>
                )}
              </div>
            ))}
          </div>
        </section>
      )}
    </div>
  );
};

// --- ESTILOS ---
const containerCenter = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '60vh' };
const listTitleStyle = { color: '#2d6a4f', fontSize: '1.2rem', fontWeight: 700, marginBottom: '20px' };

const mainCardStyle = { 
  background: '#fff', padding: '25px', borderRadius: '15px', 
  boxShadow: '0 4px 12px rgba(0,0,0,0.08)', border: '1px solid #e9ecef', maxWidth: '600px'
};

const avatarCircle = { 
  width: '60px', height: '60px', borderRadius: '50%', background: '#d8f3dc', 
  display: 'flex', alignItems: 'center', justifyContent: 'center', border: '2px solid #1b4332' 
};

const labelStyle = { fontSize: '0.8rem', fontWeight: 700, color: '#6c757d', marginBottom: '5px', display: 'block' };
const inputStyle = { padding: '8px 12px', borderRadius: '8px', border: '1px solid #ced4da', width: '100%', outline: 'none' };
const infoGrid = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', marginTop: '15px' };
const infoValue = { color: '#495057', fontSize: '0.9rem', fontWeight: 500 };

const btnSaveStyle = { background: '#2d6a4f', color: '#fff', border: 'none', borderRadius: '8px', padding: '0 15px', cursor: 'pointer' };
const btnPassStyle = { background: '#1b4332', color: '#fff', border: 'none', borderRadius: '8px', padding: '8px 15px', fontSize: '0.8rem', cursor: 'pointer' };

const userGridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' };
const userCardStyle = { background: '#fff', padding: '20px', borderRadius: '12px', border: '1px solid #dee2e6', position: 'relative' };
const smallAvatarStyle = { width: '35px', height: '35px', borderRadius: '50%', background: '#1b4332', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700 };
const userCardContent = { fontSize: '0.85rem', color: '#495057' };

const selectWrapper = { position: 'relative' };
const selectStyle = { padding: '4px 8px', borderRadius: '5px', border: '1px solid #ffcc00', background: '#fff', fontSize: '0.8rem', fontWeight: 700 };

const deleteBtnStyle = { 
  marginTop: '15px', background: 'transparent', color: '#dc3545', border: 'none', 
  fontSize: '0.8rem', fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' 
};

const badgeStyle = (tipo) => ({
  display: 'inline-block', padding: '4px 10px', borderRadius: '6px', fontSize: '0.75rem', fontWeight: 800,
  backgroundColor: tipo === 'proprietario' ? '#1b4332' : '#ffc107',
  color: tipo === 'proprietario' ? '#fff' : '#000',
  textTransform: 'uppercase'
});

export default Perfil;
